import React, { useState, useEffect } from "react";
import axios from "axios";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LabelList
} from "recharts";

function ModelAccuracy() {
  const [modelData, setModelData] = useState([]); // only this

  // Fetch data from backend API
  useEffect(() => {
    axios.get("http://localhost:5000/api/model-performance")
      .then(res => setModelData(res.data))
      .catch(err => console.error(err));
  }, []);

  return (
    <div style={{ width: "90%", margin: "40px auto", textAlign: "center" }}>
      <h2>MODEL PERFORMANCE COMPARISON: SALARY PREDICTION SYSTEM</h2>
      <p>Comparing ML Models across Key Metrics for Accuracy and Error</p>

      <ResponsiveContainer width="100%" height={400}>
        <BarChart data={modelData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis domain={[0, 1]} />
          <Tooltip />
          <Legend />

          <Bar dataKey="accuracy" fill="#FFA500" name="Accuracy (R²)">
            <LabelList dataKey="accuracy" position="top" />
          </Bar>

          <Bar dataKey="rmse" fill="#2E75B6" name="RMSE">
            <LabelList dataKey="rmse" position="top" />
          </Bar>
        </BarChart>
      </ResponsiveContainer>

      <p style={{ marginTop: "20px", fontSize: "14px", color: "gray" }}>
        Note: RMSE is scaled to 0-1 for direct visual comparison with R² Accuracy.
      </p>
    </div>
  );
}

export default ModelAccuracy;
